\begin{theorem} $($See \cref{section:projective bundle:th 1}$)$
	We have line bundles $\mathcal{L}_{0},\ldots,\mathcal{L}_{r-1}$ on $Y_{r-1}$ and an isomorphism $\Psi:Y_{r}\longrightarrow \mathbb{P}(\mathcal{E})$ over $Y_{r-1}$, where $\mathcal{E}=\mathcal{L}_{0}^{\oplus q}\oplus(\bigoplus_{j=1}^{r-1} \mathcal{L}_{j}^{\oplus q-1})$.
\end{theorem}

