\begin{theorem}$($see \cite[Theorem 2.1]{GIT}$)$ Let $x\in X$. Then 
\begin{enumerate}
	\item $x\in X^{ss}_{H}(\mathcal{L})$ if and only if $\mu^{\mathcal{L}}(x,\lambda)\geq 0$ for all one parameter subgroup $\lambda$ of $H$.
	\item $x\in X^{s}_{H}(\mathcal{L})$ if and only if $\mu^{\mathcal{L}}(x,\lambda)> 0$ for all non trivial one parameter subgroup $\lambda$ of $H$. 
\end{enumerate}
\label{HM theprem for G}
\end{theorem}

