	\item $x\in X^{s}_{H}(\mathcal{L})$ if and only if $\mu^{\mathcal{L}}(x,\lambda)< 0$ for all non trivial one parameter subgroup $\lambda$ of $H$. 
\end{enumerate}
\label{HM theprem for G}
\end{theorem}

perturbations.original:
\begin{corollary} Let $H,X, \mathcal{L}$ be as above. Let $\lambda :\mathbb{G}_{m}\rightarrow H$ be an one parameter subgroup. Then, we have 
\begin{enumerate}
	\item $x\in X^{ss}_{\lambda(\mathbb{G}_{m})}(\mathcal{L})$  if and only if both $\mu^{\mathcal{L}}(x,\lambda)$ and $\mu^{\mathcal{L}}(x,-\lambda)$ are non-negative.
	\item $x\in X^{s}_{\lambda(\mathbb{G}_{m})}(\mathcal{L})$ if and only if both $\mu^{\mathcal{L}}(x,\lambda)$ and $\mu^{\mathcal{L}}(x,-\lambda)$ are positive.
\end{enumerate}
\label{HM theorem}
\end{corollary}

