\begin{lemma}$($See \cite[Lemma 5.1]{Ses2}$)$
Let $x=bwP/P$. 
Let $\lambda\in \overline{C(B)}$ be a one parameter subgroup. Then we have \[\mu^{\mathcal{L}(\chi)}(x,\lambda)=-\langle w(\chi),\lambda\rangle.\]
$($The sign here is negative because we are using left action of P on G/P while in \cite[Lemma 5.1]{Ses2}  the action is on the right.$)$
\label{CSS}
\end{lemma}

